	.TITLE	FILL	.PROC	M680002	.REF	LIB	.REF	GESMEM	.REF	FOS	.REF	SM8	.REF	DRIVERS	.REF	GRA	.LOC	0OPDDIS:	.BLKB	4OBUDIS:	.BLKB	20LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	.W	LIB,?GCHDIS	; D6 <-- canal cran	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre cran	LOAD.L	D4,#4		; D4 <-- longueur demande	LOAD.L	A4,#(A6)+OPDDIS	; A4 <-- ^buffer	.W	FOS,?RSTATUS	; demande le ^rel !	JUMP,NE ERFAT	LOAD.L	A2,(A6)+OPDDIS	; A2 <-- ^descripteur de la fentreLOOP:	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#100	LOAD.W	D2,#SETDOT	.W	LIB,?DRCERCLE	LOAD.W	D3,#160	SWAP.W	D3	LOAD.W	D3,#160	LOAD.W	D4,#20	LOAD.W	D2,#SETDOT	.W	LIB,?DRCERCLE	LOAD.W	D3,#240	SWAP.W	D3	LOAD.W	D3,#240	LOAD.W	D4,#40	LOAD.W	D2,#SETDOT	.W	LIB,?DRCERCLE	LOAD.B	D3,#AFCCMO	.W	LIB,?AFCAR	LOAD.B	(A2)+ODFTRA+0,#B'00000001	LOAD.B	(A2)+ODFTRA+1,#B'00000010	LOAD.B	(A2)+ODFTRA+2,#B'00000100	LOAD.B	(A2)+ODFTRA+3,#B'00001000	LOAD.B	(A2)+ODFTRA+4,#B'00010000	LOAD.B	(A2)+ODFTRA+5,#B'00100000	LOAD.B	(A2)+ODFTRA+6,#B'01000000	LOAD.B	(A2)+ODFTRA+7,#B'10000000	LOAD.W	D4,#200	SWAP.W	D4	LOAD.W	D4,#200	CALL	_GRA_FILLO	CALL	_GRA_FILLC	LOAD.B	D3,#AFSCMO	.W	LIB,?AFCAR	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWFILLO	SWAP.W	D4	LOAD.L	(A3)+1,D4	LOAD.B	(A3)+5,#DRAWFILLC	LOAD.W	D3,#5+1;	.W	LIB,?STRING	.W	LIB,?IFCAR	JUMP,NE	LOOP	COMP.W	D3,#END	JUMP,NE LOOPERFAT:	EXIT;-----------\; _GRA_FILLO >;===========/; Rempli une surface quelconque.; in	A2.L	^description de la fentre;	D4.L	point initial (y;x); out	D7.W	erreur; mod	D7.W; use	D0 no bit		A0 ^byte;	D1 lg segment		A1;	D2			A2 ^descripteur;	D3 P(x)			A3;	D4 P(y)			A4;	D5 reste (A6-A5)	A5 ^liste;	D6 nb pts sur stack	A6 ^stack;	D7 erreur		A7 SP;	|-------| <-- A5;	|   |   |;	|   |   | liste de segments horizontaux;	|  \|/  |;	|       |;	|       |;	|  /|\  |;	|   |   | stack de points;	|-------|;	          <-- A6	.MACRO	FILL_INCX	INC.B	D0	COMP.B	D0,#8	JUMP',LO %1	CLR.B	D0	LOAD.L	A0,#(A0)+1024%1:	INC.W	D3		; X <-- X+1	.ENDMACRO	.MACRO	FILL_DECX	DEC.B	D0	JUMP',NC %1	LOAD.B	D0,#8-1	LOAD.L	A0,#(A0)-1024%1:	DEC.W	D3		; X <-- X-1	.ENDMACRO	.MACRO	FILL_INCX8	LOAD.L	A0,#(A0)+1024	ADD.W	D3,#8		; X <-- X+8	.ENDMACRO	.MACRO	FILL_DECX8	LOAD.L	A0,#(A0)-1024	SUB.W	D3,#8		; X <-- X-8	.ENDMACRO	.MACRO	FILL_INCY	INC.L	A0	INC.W	D4		; Y <-- Y+1	.ENDMACRO	.MACRO	FILL_DECY	DEC.L	A0	DEC.W	D4		; Y <-- Y-1	.ENDMACRO	.MACRO	FILL_PUSH	INC.W	D6	SUB.L	D5,#4	JUMP,LO FILL_OVERFLOW	LOAD.W	(-A6),D3	; PUSH (x,y)	LOAD.W	(-A6),D4	.ENDMACRO_GRA_FILLO:	PUSHM.L	D0..D6,A0..A6	LOAD.L	D0,D4		; D0 <-- point initial	CALL	_GRA_FILLC	; libre si pas encore fait !	LOAD.W	D3,#16		; D3 <-- prend tout, hum	LOAD.L	D4,#LGRAF*10	; D4 <-- minimum	LOAD.L	D5,#500000	; D5 <-- maximumLOAD.W D1,#MTYPCP;;?	LOAD.W	D1,#MTYPBD	; D1 <-- type driver bios;;?	LOAD.L	A1,(A2)+ODFBAS	; A1 <-- ^base du driver	.W	GESMEM,?GETPMEM	; demande de la mmoire	JUMP,NE	FILL_EXIT	LOAD.L	(A2)+ODFFIP,A4	; mm ^table	LOAD.L	A5,A4		; A5 <-- ^liste	LOAD.L	D5,D4		; D5 <-- reste	SUB.L	D5,#2		; D5 <-- place pour terminateur	ADD.L	A4,D4	LOAD.L	A6,A4		; A6 <-- ^stack	CLR.W	D6		; D6 <-- place utilise sur le stack	ADD.W	D0,(A2)+ODFWBX	; D0 <-- X initial	SWAP.W	D0	ADD.W	D0,(A2)+ODFWBY	; D0 <-- Y initial	SWAP.W	D0	INC.W	D6	SUB.L	D5,#4	LOAD.L	(-A6),D0	; PUSH (x,y) initial; Boucle principale. Traite un point sur le stack.FILL_LOOP:	SUB.L	D5,#4	DEC.W	D6		; stack vide ?	JUMP,NS FILL_END	; oui => c'est fini	LOAD.W	D4,(A6+)	; POP (x,y)	LOAD.W	D3,(A6+)	CALL	GETPBNB		; A0/D0 <-- ^point; Cherche l'extrme droite Xright.FILL_XRIGHT:	TSET.B	(A0):D0	JUMP,BS FILL_LOOP	PUSHM.L	D0,D3,A0	JUMP'	50$30$:	TEST.B	D0	JUMP',NE 40$35$:	TEST.B	(A0)	JUMP',NE 40$	SET.B	(A0)	FILL_INCX8	COMP.W	D3,(A2)+ODFWEX	; dpasse  droite ?	JUMP,GE FILL_OUT	JUMP	35$40$:	TSET.B	(A0):D0	JUMP',BS 60$50$:	FILL_INCX 52$	COMP.W	D3,(A2)+ODFWEX	; dpasse  droite ?	JUMP,GE FILL_OUT	JUMP	30$60$:	FILL_DECX 62$	LOAD.W	D1,D3		; D1 <-- Xright	POPM.L	D0,D3,A0; Cherche l'extrme gauche Xleft.FILL_XLEFT:	JUMP'	50$30$:	COMP.B	D0,#7	JUMP',NE 40$35$:	TEST.B	(A0)	JUMP',NE 40$	SET.B	(A0)	FILL_DECX8	COMP.W	D3,(A2)+ODFWBX	; dpasse  gauche ?	JUMP,LT FILL_OUT	JUMP	35$40$:	TSET.B	(A0):D0	JUMP',BS 60$50$:	FILL_DECX 52$	COMP.W	D3,(A2)+ODFWBX	; dpasse  gauche ?	JUMP,LT FILL_OUT	JUMP	30$60$:	FILL_INCX 62$	SUB.W	D1,D3		; D1 <-- Xleft - Xright	INC.W	D1		; D1 <-- longueur; Mmorise la ligne dans la liste.	SUB.L	D5,#LGRAF	JUMP,LO FILL_OVERFLOW	PUSHM.L	D3,D4	SUB.W	D4,(A2)+ODFWBY	LOAD.W	(A5+),D4	; liste <-- Y	SUB.W	D3,(A2)+ODFWBX	LOAD.W	(A5+),D3	; liste <-- X dbut	ADD.W	D3,D1	LOAD.W	(A5+),D3	; liste <-- X fin	POPM.L	D3,D4; Balaye la ligne en-dessus.FILL_SCANUP:	PUSHM.L	D0,D1,D3,D4,A0	FILL_DECY	COMP.W	D4,(A2)+ODFWBY	; dpasse en haut ?	JUMP,LT FILL_OUT20$:	TEST.B	(A0):D0		; saute les points allums	JUMP',BC 35$25$:	FILL_INCX 27$	DEC.W	D1	JUMP,NE 20$	JUMP'	80$30$:	TEST.B	D0	JUMP',NE 33$31$:	COMP.W	D1,#8	JUMP',LO 33$	TEST.B	(A0)	JUMP',NE 33$	FILL_INCX8	SUB.W	D1,#8	JUMP',EQ 37$	JUMP	31$33$:	TEST.B	(A0):D0		; saute les points teints	JUMP',BS 40$35$:	FILL_INCX 36$	DEC.W	D1	JUMP,NE 30$37$:	DEC.W	D3	FILL_PUSH		; PUSH (x-1,y);	INC.W	D3	JUMP'	80$40$:	DEC.W	D3	FILL_PUSH		; PUSH (x-1,y)	INC.W	D3	JUMP	25$80$:	POPM.L	D0,D1,D3,D4,A0; Balaye la ligne en-dessous.FILL_SCANDOWN:	FILL_INCY	COMP.W	D4,(A2)+ODFWEY	; dpasse en bas ?	JUMP,GE FILL_OUT20$:	TEST.B	(A0):D0		; saute les points allums	JUMP',BC 35$25$:	FILL_INCX 27$	DEC.W	D1	JUMP,NE 20$	JUMP'	80$30$:	TEST.B	D0	JUMP',NE 33$31$:	COMP.W	D1,#8	JUMP',LO 33$	TEST.B	(A0)	JUMP',NE 33$	FILL_INCX8	SUB.W	D1,#8	JUMP',EQ 37$	JUMP	31$33$:	TEST.B	(A0):D0		; saute les points teints	JUMP',BS 40$35$:	FILL_INCX 36$	DEC.W	D1	JUMP,NE 30$37$:	DEC.W	D3	FILL_PUSH		; PUSH (x-1,y);	INC.W	D3	JUMP'	80$40$:	DEC.W	D3	FILL_PUSH		; PUSH (x-1,y)	INC.W	D3	JUMP	25$80$:	JUMP	FILL_LOOPFILL_OVERFLOW:	LOAD.W	D7,#ERNEMEM	; D7 <-- forme trop complique	JUMP'	FILL_EXITFILL_OUT:	LOAD.W	D7,#ERDIOUT	; D7 <-- a dborde	JUMP'	FILL_EXITFILL_END:	LOAD.W	(A5),#-1	; liste <-- terminateur	CALL	FILL_TRAME	; met la vraie trameFILL_EXIT:	POPM.L	D0..D6,A0..A6	TEST.W	D7		; retour EQ/NE	RET;-----------\; _GRA_FILLC >;===========/; Rend la mmoire des points allums.; in	A2.L	^description de la fentre; out	-; mod	-_GRA_FILLC:	PUSHM.L	D1,D7,A1,A4	TEST.L	(A2)+ODFFIP	; table existe ?	JUMP',EQ 90$		; non => 90$				; oui =>	LOAD.L	A4,(A2)+ODFFIP	; A4 <-- ^mmoireLOAD.W D1,#MTYPCP;;?	LOAD.W	D1,#MTYPBD	; D1 <-- type driver bios;;?	LOAD.L	A1,(A2)+ODFBAS	; A1 <-- ^base du driver	.W	GESMEM,?GIVMEM	; rend la mmoire90$:	POPM.L	D1,D7,A1,A4	RET;-----------\\; FILL_TRAME >;-----------/     ; Redessine toute la surface avec la trame choisie.; in	A2.L	^description de la fentre; out	-; mod	-FILL_TRAME:	PUSHM.L	D0..D4,A3,A4	COMP.L	(A2)+ODFTRA+0,#-1	JUMP',NE 05$	COMP.L	(A2)+ODFTRA+4,#-1	JUMP,EQ 90$05$:	LOAD.L	A4,(A2)+ODFFIP	; A4 <-- ^liste10$:	LOAD.W	D4,(A4+)	; D4 <-- Y	COMP.W	D4,#-1	JUMP,EQ 90$	LOAD.L	A3,#(A2)+ODFTRA	LOAD.W	D3,D4	AND.W	D3,#B'111	ADD.W	A3,D3		; A3 <-- ^byte de la trame	LOAD.B	D1,(A3)		; D1 <-- byte de la trame	LOAD.W	D3,(A4+)	; D3 <-- X	LOAD.W	D2,(A4+)	SUB.W	D2,D3		; D2 <-- longueur	NOT.B	D1	JUMP,EQ 10$	ADD.W	D3,(A2)+ODFWBX	ADD.W	D4,(A2)+ODFWBY	CALL	GETPBNB		; A0/D0 <-- ^point  gauche; Travail de dbut.	TEST.B	D0	JUMP',EQ 40$	LOAD.B	D3,D1		; D3 <-- byte trame	SR.B	D3,D0	RL.B	D3,D0	LOAD.W	D4,#8	SUB.W	D4,D0	COMP.W	D2,D4	JUMP',HS 30$	SUB.W	D4,D2	SL.B	D3,D4	RR.B	D3,D4	NOT.B	D3	AND.B	(A0),D3	JUMP	10$30$:	NOT.B	D3	AND.B	(A0),D3	SUB.W	D2,D4	FILL_INCX8	CLR.B	D0; Travail du milieu.40$:	COMP.W	D2,#8	JUMP',LO 60$	LOAD.W	D4,D2	SR.W	D4,#3		; D4 <-- nb de bytes	DEC.W	D4		; D4 <-- -1  cause NMO	NOT.B	D145$:	AND.B	(A0),D1	FILL_INCX8	DECJ.W,NMO D4,45$	NOT.B	D1; Travail de fin.60$:	AND.B	D2,#B'111	SUB.B	D2,#8	NEG.B	D2	JUMP,EQ 10$	LOAD.B	D3,D1		; D3 <-- byte trame	SL.B	D3,D2	RR.B	D3,D2	NOT.B	D3	AND.B	(A0),D3	JUMP	10$90$:	POPM.L	D0..D4,A3,A4	RETGETPBNB:	PUSHM.L	D3,D4	LOAD.B	D0,D3	AND.W	D0,#B'111	; D0 <-- no du bit dans le byte	AND.W	D4,#H'3FF	; masque coordonne Y	AND.L	D3,#H'3F8	; masque coordonne X	SL.L	D3,#7	OR.W	D3,D4	TSET.L	D3:#19		; ajoute bit pour H'80000	LOAD.L	A0,D3		; A0 <-- adresse dans l'cran	POPM.L	D3,D4	RETVAR:	.FILLB	LGVAR,0	.END	START